import java.io.*;
import org.owasp.encoder.Encode;

public class XSSFixedCode {

    public static void main(String[] args) {
        // Simulating user input
        String userInput = "<script>alert('XSS Vulnerability')</script>";

        // Properly handling user input by escaping special characters
        String sanitizedInput = Encode.forHtml(userInput);

        try {
            BufferedWriter writer = new BufferedWriter(new FileWriter("output.html"));
            writer.write("<html><body>");
            writer.write("<h1>Welcome, " + sanitizedInput + "</h1>");
            writer.write("</body></html>");
            writer.close();
            System.out.println("Output HTML file created successfully.");
        } catch (IOException e) {
            System.out.println("Error writing to output file: " + e.getMessage());
        }
    }
}

